<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Courses';
if(isset($_GET['delete'])){executeSql('DELETE FROM courses WHERE id=?',[(int)$_GET['delete']]); flash('success','Deleted'); header('Location: index.php'); exit;}
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); $id=(int)($_POST['id']??0); $p=[post('name'),post('duration'),(float)post('fees','0'),(int)post('subjects_count','0'),(int)post('seats','0'),(int)post('semester_count','1')]; if($id){$p[]=$id;executeSql('UPDATE courses SET name=?,duration=?,fees=?,subjects_count=?,seats=?,semester_count=? WHERE id=?',$p);}else{executeSql('INSERT INTO courses(name,duration,fees,subjects_count,seats,semester_count) VALUES (?,?,?,?,?,?)',$p);} header('Location: index.php'); exit; }
$edit=get('edit')?fetchOne('SELECT * FROM courses WHERE id=?',[(int)get('edit')]):null; $rows=fetchAll('SELECT * FROM courses ORDER BY id DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="id" value="<?=$edit['id']??0?>"><div class="col"><input name="name" class="form-control" placeholder="Course" value="<?=e($edit['name']??'')?>" required></div><div class="col"><input name="duration" class="form-control" placeholder="Duration" value="<?=e($edit['duration']??'')?>" required></div><div class="col"><input name="fees" class="form-control" type="number" step="0.01" value="<?=e((string)($edit['fees']??0))?>"></div><div class="col"><input name="subjects_count" class="form-control" type="number" value="<?=e((string)($edit['subjects_count']??0))?>"></div><div class="col"><input name="seats" class="form-control" type="number" value="<?=e((string)($edit['seats']??0))?>"></div><div class="col"><input name="semester_count" class="form-control" type="number" value="<?=e((string)($edit['semester_count']??1))?>"></div><div class="col"><button class="btn btn-primary">Save</button></div></form><hr><table class="table"><tr><th>Name</th><th>Duration</th><th>Fees</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['duration'])?></td><td><?=number_format((float)$r['fees'],2)?></td><td><a href="?edit=<?=$r['id']?>">Edit</a> | <a onclick="return confirm('Delete?')" href="?delete=<?=$r['id']?>">Delete</a></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
